
import {computed, ComputedRef, defineComponent, PropType, toRefs} from "vue";
import {Recipe, Step} from "@/tastebuddy/types";
import {IonItem, IonText, useIonRouter} from "@ionic/vue";
import RecipeHero from "@/components/recipe/RecipeHero.vue";
import ItemList from "@/components/recipe/ItemList.vue";
import TwoColumnLayout from "@/components/layout/TwoColumnLayout.vue";

export default defineComponent({
    name: 'RecipePreview',
    props: {
        recipe: {
            type: Object as PropType<Recipe>,
            required: true
        },
        noDescription: {
            type: Boolean,
            default: false
        }
    },
    components: {
        IonItem, IonText,
        TwoColumnLayout,
        ItemList,
        RecipeHero
    },
    setup(props: any) {
        const {recipe} = toRefs(props)
        const firstStep: ComputedRef<Step | undefined> = computed(() => recipe.value?.steps[0])
        const items = computed(() => recipe.value?.getItems() ?? [])

        const router = useIonRouter();
        const toRecipe = () => {
            router.push({name: 'Recipe', params: {id: recipe.value?.getId()}})
        }

        return {
            firstStep, items,
            toRecipe
        }
    }
});
